  66→function serializeSvg(svgElement) {
  67→  const clone = svgElement.cloneNode(true);
  68→  clone.setAttribute('xmlns', 'http://www.w3.org/2000/svg');
  69→  clone.setAttribute('xmlns:xlink', 'http://www.w3.org/1999/xlink');
  70→  clone.removeAttribute('style');
  71→
  72→  if (!clone.getAttribute('viewBox')) {
  73→    const width = clone.getAttribute('width') || '100';
  74→    const height = clone.getAttribute('height') || '100';
  75→    clone.setAttribute('viewBox', `0 0 ${width} ${height}`);
  76→  }
  77→
  78→  inlineComputedStyles(svgElement, clone);
  79→  return new XMLSerializer().serializeToString(clone);
  80→}
