 188→function parseTransform(transform = '') {
 189→  let matrix = new DOMMatrix();
 190→  const pattern = /([a-zA-Z]+)\(([^)]*)\)/g;
 191→  let match = pattern.exec(transform);
 192→  while (match) {
 193→    const [, name, argsString] = match;
 194→    const args = parseNumberList(argsString);
 195→    switch (name) {
 196→      case 'translate':
 197→        matrix = matrix.multiply(new DOMMatrix().translate(args[0] || 0, args[1] || 0));
 198→        break;
 199→      case 'scale':
 200→        matrix = matrix.multiply(new DOMMatrix().scale(args[0] ?? 1, args[1] ?? args[0] ?? 1));
 201→        break;
 202→      case 'rotate':
 203→        if (args.length >= 3) {
 204→          matrix = matrix.multiply(new DOMMatrix().translate(args[1], args[2]).rotate(args[0]).translate(-args[1], -args[2]));
 205→        } else {
 206→          matrix = matrix.multiply(new DOMMatrix().rotate(args[0] || 0));
 207→        }
 208→        break;
 209→      case 'matrix':
 210→        if (args.length >= 6) {
 211→          matrix = matrix.multiply(new DOMMatrix([args[0], args[1], args[2], args[3], args[4], args[5]]));
 212→        }
 213→        break;
 214→      default:
 215→        break;
 216→    }
 217→    match = pattern.exec(transform);
 218→  }
 219→  return matrix;
 220→}
 221→
 222→function matrixIsIdentity(matrix) {
 223→  return (
 224→    Math.abs(matrix.a - 1) < 1e-8
 225→    && Math.abs(matrix.b) < 1e-8
 226→    && Math.abs(matrix.c) < 1e-8
 227→    && Math.abs(matrix.d - 1) < 1e-8
 228→    && Math.abs(matrix.e) < 1e-8
 229→    && Math.abs(matrix.f) < 1e-8
 230→  );
 231→}
 232→
 233→function parseViewBox(svgElement) {
 234→  const values = parseNumberList(svgElement.getAttribute('viewBox') || '');
 235→  if (values.length !== 4) {
 236→    return {
 237→      minX: 0,
 238→      minY: 0,
 239→      width: Number(svgElement.getAttribute('width')) || 0,
 240→      height: Number(svgElement.getAttribute('height')) || 0,
 241→    };
 242→  }
 243→  return {
 244→    minX: values[0],
 245→    minY: values[1],
 246→    width: values[2],
 247→    height: values[3],
 248→  };
 249→}
 250→
 251→function getLocalMatrix(element) {
 252→  const transformAttr = element.getAttribute('transform') || '';
 253→  let matrix = new DOMMatrix();
 254→
 255→  if (element.tagName.toLowerCase() === 'svg') {
 256→    const x = Number(element.getAttribute('x')) || 0;
 257→    const y = Number(element.getAttribute('y')) || 0;
 258→    const width = Number(element.getAttribute('width')) || 0;
 259→    const height = Number(element.getAttribute('height')) || 0;
 260→    const viewBox = parseViewBox(element);
 261→    const scaleX = viewBox.width ? width / viewBox.width : 1;
 262→    const scaleY = viewBox.height ? height / viewBox.height : 1;
 263→    matrix = matrix
 264→      .translate(x, y)
 265→      .scale(scaleX || 1, scaleY || 1)
 266→      .translate(-viewBox.minX, -viewBox.minY);
 267→  }
 268→
 269→  if (transformAttr) {
 270→    matrix = matrix.multiply(parseTransform(transformAttr));
 271→  }
 272→
 273→  return matrix;
 274→}
 275→
 276→function parseColor(styleValue) {
 277→  if (!styleValue || styleValue === 'none') return null;
 278→  const normalized = String(styleValue).trim();
 279→
 280→  if (normalized.startsWith('#')) {
 281→    const hex = normalized.slice(1);
 282→    const chunks = hex.length === 3
 283→      ? hex.split('').map((value) => value + value)
 284→      : [hex.slice(0, 2), hex.slice(2, 4), hex.slice(4, 6)];
 285→    return chunks.map((value) => parseInt(value, 16) / 255);
 286→  }
 287→
 288→  const rgb = normalized.match(/rgba?\(([^)]+)\)/i);
 289→  if (rgb) {
 290→    const values = rgb[1].split(',').map((value) => Number.parseFloat(value.trim()));
 291→    return values.slice(0, 3).map((value) => value / 255);
 292→  }
 293→
 294→  return null;
 295→}
 296→
 297→function computeStyle(element) {
 298→  const style = window.getComputedStyle(element);
 299→  const fill = parseColor(style.fill);
 300→  const stroke = parseColor(style.stroke);
 301→  const strokeWidth = Number.parseFloat(style.strokeWidth) || 0;
 302→  const lineCap = style.strokeLinecap || 'butt';
 303→  const lineJoin = style.strokeLinejoin || 'miter';
 304→  const dashArray = parseNumberList(style.strokeDasharray || '');
 305→  const fontSize = Number.parseFloat(style.fontSize) || 12;
 306→  const opacity = Number.parseFloat(style.opacity || '1') || 1;
 307→  const fillOpacity = fill ? opacity * (Number.parseFloat(style.fillOpacity || '1') || 1) : 0;
 308→  const strokeOpacity = stroke ? opacity * (Number.parseFloat(style.strokeOpacity || '1') || 1) : 0;
 309→
 310→  return {
 311→    fill,
 312→    stroke,
 313→    strokeWidth,
 314→    lineCap,
 315→    lineJoin,
 316→    dashArray,
 317→    fontSize,
 318→    fontFamily: style.fontFamily || 'Arial',
 319→    fontWeight: style.fontWeight || '400',
 320→    textAnchor: style.textAnchor || 'start',
 321→    dominantBaseline: style.dominantBaseline || 'auto',
 322→    fillOpacity,
 323→    strokeOpacity,
 324→  };
 325→}
 326→
 327→function lineCapCode(value) {
 328→  if (value === 'round') return 1;
 329→  if (value === 'square') return 2;
 330→  return 0;
 331→}
 332→
 333→function lineJoinCode(value) {
 334→  if (value === 'round') return 1;
 335→  if (value === 'bevel') return 2;
 336→  return 0;
 337→}
 338→
 339→function normalizeSweep(delta, sweepFlag) {
 340→  let result = delta;
 341→  if (sweepFlag && result < 0) result += Math.PI * 2;
 342→  if (!sweepFlag && result > 0) result -= Math.PI * 2;
 343→  return result;
 344→}
 345→
 346→function buildArcPoints(start, rx, ry, rotation, largeArcFlag, sweepFlag, end) {
 347→  if (!start || !end) return [end];
 348→  if (Math.abs(rotation) > 1e-6 || Math.abs(rx - ry) > 1e-6) return [end];
 349→  const radius = Math.abs(rx);
 350→  const dx = end.x - start.x;
 351→  const dy = end.y - start.y;
 352→  const chordLength = Math.hypot(dx, dy);
 353→  if (chordLength < 1e-6 || radius < chordLength / 2) return [end];
 354→
 355→  const midX = (start.x + end.x) / 2;
 356→  const midY = (start.y + end.y) / 2;
 357→  const halfChord = chordLength / 2;
 358→  const offsetLength = Math.sqrt(Math.max(0, radius * radius - halfChord * halfChord));
 359→  const ux = -dy / chordLength;
 360→  const uy = dx / chordLength;
 361→
 362→  const centers = [
 363→    { x: midX + ux * offsetLength, y: midY + uy * offsetLength },
 364→    { x: midX - ux * offsetLength, y: midY - uy * offsetLength },
 365→  ];
 366→
 367→  for (const center of centers) {
 368→    const startAngle = Math.atan2(start.y - center.y, start.x - center.x);
 369→    const endAngle = Math.atan2(end.y - center.y, end.x - center.x);
 370→    const sweepDelta = normalizeSweep(endAngle - startAngle, Boolean(sweepFlag));
 371→    const isLarge = Math.abs(sweepDelta) > Math.PI;
 372→    if (isLarge !== Boolean(largeArcFlag)) continue;
 373→
 374→    const points = [];
 375→    for (let index = 1; index <= ARC_SEGMENTS; index += 1) {
 376→      const angle = startAngle + (sweepDelta * index) / ARC_SEGMENTS;
 377→      points.push({
 378→        x: center.x + radius * Math.cos(angle),
 379→        y: center.y + radius * Math.sin(angle),
 380→      });
 381→    }
 382→    return points;
 383→  }
 384→
 385→  return [end];
 386→}
