 856→function renderPolygonLike(builder, element, closePath) {
 857→  const points = parsePoints(element.getAttribute('points') || '');
 858→  if (!points.length) return;
 859→  const style = computeStyle(element);
 860→  builder.write('q');
 861→  builder.applyStyle(style);
 862→  emitPathFromPoints(builder, points, closePath);
 863→
 864→  if (style.fill && style.stroke && style.strokeWidth > 0) builder.write('B');
 865→  else if (style.fill) builder.write('f');
 866→  else if (style.stroke && style.strokeWidth > 0) builder.write('S');
 867→  builder.write('Q');
 868→}
